{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic CT Volume",
      "simple": "Choose the Pelvic Volume from the Input CT Volume dropdown.",
      "detailed": "This CT scan of the pelvis is the foundation for all subsequent steps—it provides the bone anatomy needed to segment the pelvis and identify fracture fragments. Select the correct volume (typically labeled as the pelvic series) from the dropdown list."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment the Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button to begin automatic pelvic segmentation.",
      "detailed": "This step generates a 3D model of the intact pelvic bone from the CT scan. The pelvic segmentation serves as the reference anatomy against which fracture fragments will be aligned during reduction."
    },
    {
      "step_id": "cb_step_3",
      "title": "Identify Fracture Lines",
      "simple": "Click the 'Run Step 2: Segment Fractures' button to detect and segment the fracture fragments.",
      "detailed": "The software automatically detects fracture lines and separates the pelvic bone into individual fragments. This is critical for understanding the fracture pattern and planning the reduction and screw fixation."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Unnecessary Fragments",
      "simple": "In the fragment list, untick any fragments you want to exclude from the planning process.",
      "detailed": "Not all fracture fragments may be relevant to your surgical plan—small or nondisplaced fragments can clutter the model. Exclude them now to focus the template generation and reduction steps on the clinically important fragments."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click the 'Run Step 3: Generate Template' button to create a template for fracture reduction.",
      "detailed": "This step computes a preliminary template that defines the target alignment for each fracture fragment relative to the intact pelvis. The template guides the automated reduction and provides a starting point if manual adjustment is needed later."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce Fragments",
      "simple": "Click the 'Run Step 4: Register_Reduce' button to automatically align the fracture fragments to the template.",
      "detailed": "The software performs an automated registration to reposition each fragment to its intended anatomical location, creating a virtual reduction. This digital reduction is the foundation for screw planning and can be refined manually if necessary."
    },
    {
      "step_id": "cb_step_7",
      "title": "Decide on Manual Adjustment",
      "simple": "Choose whether to manually adjust a fragment or skip to screw planning.",
      "detailed": "If the automatic reduction result is satisfactory, proceed directly to screw planning. If a fragment is misaligned—for example, a rotated or displaced piece that needs finer correction—select 'Yes, adjust' to fine-tune its position before planning screws."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment to Adjust",
      "simple": "In the Fragment dropdown, choose the fragment that needs manual adjustment.",
      "detailed": "Pick the specific fracture fragment that requires repositioning or rotation correction. Selecting the correct fragment ensures that your manual adjustments apply to the intended piece of bone."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Position and Rotation",
      "simple": "Use the transform tools to manually adjust the selected fragment's position and rotation as needed.",
      "detailed": "Fine-tune the alignment of the fragment to achieve an anatomically correct reduction. Precise fragment positioning is essential for optimal screw placement and long-term fracture stability."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Manual Adjustments",
      "simple": "Click the 'Apply adjustments' button to save your manual changes.",
      "detailed": "This finalizes your manual tweaks and updates the reduction model with the corrected fragment position, readying it for screw planning."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Insertion",
      "simple": "Click the 'Run Step 5: Plan Screws' button to automatically plan screw trajectories.",
      "detailed": "The software analyzes the reduced pelvis and fracture geometry to suggest optimal screw positions, orientations, and lengths. These trajectories aim to achieve stable fixation while avoiding critical neurovascular structures."
    },
    {
      "step_id": "cb_step_12",
      "title": "Decide on Screw Trajectory Editing",
      "simple": "Choose whether to manually edit the suggested screw trajectories or accept them as-is.",
      "detailed": "If the automatically planned screws are satisfactory, you can finish. Select 'Yes, edit' to refine screw positions for better biomechanics or to avoid important anatomical structures such as the sacral neural foramina or the acetabulum."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "Manually adjust the position and rotation of the screw trajectories using the transform tools.",
      "detailed": "Fine-tune each screw's entry point, direction, and depth to ensure safe and effective fixation. This step is crucial for avoiding neurovascular structures and achieving optimal bone purchase."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws from Edits",
      "simple": "Click the 'Regenerate screws from edited lines' button to update the screw models based on your adjustments.",
      "detailed": "This recalculates the screw geometry—including length and diameter—to match the edited trajectory lines, producing the final screw models for the surgical plan."
    },
    {
      "step_id": "cb_step_15",
      "title": "Finish Screw Editing",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to finalize the screw planning.",
      "detailed": "This exits the editing mode and confirms the screw trajectories are complete, finalizing the surgical plan. The output models are now ready for review or export."
    }
  ]
}
